/**
 * rotation-benchmark.ts -- Wallington Rotation benchmark suite
 *
 * Measures each bottleneck before and after optimization.
 * Following Ch17 §R0-R5: measure, eliminate, measure again.
 *
 * Usage: gnode run src/benchmarks/rotation-benchmark.ts
 */

import {
  createVoidBoundary,
  updateVoidBoundary,
  complementDistribution,
  decayVoidBoundary,
  giniCoefficient,
  shannonEntropy,
  measure,
  flattenStack,
  createBoundaryStack,
  createTimescaleBoundary,
  tickBoundaryStack,
  buleyeanWeight,
  teleportDeficit,
  sampleComplement,
  createWalker,
  c0Choose,
  c0Update,
  c1Measure,
  c2c3Adapt,
} from '../void';

// ============================================================================
// Benchmark harness
// ============================================================================

interface BenchResult {
  name: string;
  ops: number;
  nsPerOp: number;
  opsPerSec: number;
}

function bench(
  name: string,
  fn: () => void,
  warmup = 1000,
  iterations = 100000
): BenchResult {
  // Warmup
  for (let i = 0; i < warmup; i++) fn();

  const start = performance.now();
  for (let i = 0; i < iterations; i++) fn();
  const elapsed = performance.now() - start;

  const nsPerOp = (elapsed * 1e6) / iterations;
  const opsPerSec = iterations / (elapsed / 1000);

  return { name, ops: iterations, nsPerOp, opsPerSec };
}

function report(results: BenchResult[]): void {
  console.log(
    '\n╔══════════════════════════════════════════════════════════════╗'
  );
  console.log(
    '║           Wallington Rotation Benchmark Results             ║'
  );
  console.log(
    '╠══════════════════════════════════════════════════════════════╣'
  );
  for (const r of results) {
    const name = r.name.padEnd(35);
    const ns = r.nsPerOp.toFixed(1).padStart(10);
    const ops = formatNumber(r.opsPerSec).padStart(12);
    console.log(`║ ${name} ${ns} ns/op  ${ops} ops/s ║`);
  }
  console.log(
    '╚══════════════════════════════════════════════════════════════╝'
  );
}

function formatNumber(n: number): string {
  if (n >= 1e9) return (n / 1e9).toFixed(2) + 'B';
  if (n >= 1e6) return (n / 1e6).toFixed(2) + 'M';
  if (n >= 1e3) return (n / 1e3).toFixed(2) + 'K';
  return n.toFixed(0);
}

// ============================================================================
// Benchmark scenarios
// ============================================================================

function buildBoundary(
  dims: number,
  rounds: number
): ReturnType<typeof createVoidBoundary> {
  const b = createVoidBoundary(dims);
  const rng = () => Math.random();
  for (let r = 0; r < rounds; r++) {
    const dim = Math.floor(rng() * dims);
    updateVoidBoundary(b, dim);
  }
  return b;
}

function buildStack(layers: number, dimsPerLayer: number, rounds: number) {
  const timescales = [
    'instant',
    'seconds',
    'minutes',
    'hours',
    'days',
    'weeks',
    'months',
  ] as const;
  const tbs = [];
  for (let i = 0; i < layers; i++) {
    const tb = createTimescaleBoundary(
      `layer-${i}`,
      timescales[i % timescales.length],
      dimsPerLayer
    );
    // Populate with rejections
    for (let r = 0; r < rounds; r++) {
      updateVoidBoundary(tb.boundary, Math.floor(Math.random() * dimsPerLayer));
    }
    tbs.push(tb);
  }
  return createBoundaryStack('bench-stack', tbs);
}

// ============================================================================
// Run
// ============================================================================

const results: BenchResult[] = [];

// --- R1: giniCoefficient O(N²) ---
const giniValues16 = Array.from({ length: 16 }, () => Math.random() * 100);
const giniValues64 = Array.from({ length: 64 }, () => Math.random() * 100);
const giniValues256 = Array.from({ length: 256 }, () => Math.random() * 100);
const giniValues1024 = Array.from({ length: 1024 }, () => Math.random() * 100);

results.push(bench('gini(16)', () => giniCoefficient(giniValues16)));
results.push(bench('gini(64)', () => giniCoefficient(giniValues64)));
results.push(
  bench('gini(256)', () => giniCoefficient(giniValues256), 100, 10000)
);
results.push(
  bench('gini(1024)', () => giniCoefficient(giniValues1024), 10, 1000)
);

// --- R2: complementDistribution ---
const b16 = buildBoundary(16, 100);
const b64 = buildBoundary(64, 500);
const b256 = buildBoundary(256, 2000);
const b1024 = buildBoundary(1024, 5000);

results.push(bench('complement(16)', () => complementDistribution(b16)));
results.push(bench('complement(64)', () => complementDistribution(b64)));
results.push(bench('complement(256)', () => complementDistribution(b256)));
results.push(bench('complement(1024)', () => complementDistribution(b1024)));

// --- R3: decayVoidBoundary ---
const decayB = buildBoundary(256, 2000);
results.push(
  bench('decay(256)', () => {
    decayVoidBoundary(decayB, 0.01);
  })
);

// --- R4: flattenStack ---
const stack7x16 = buildStack(7, 16, 50);
const stack7x64 = buildStack(7, 64, 200);

results.push(bench('flattenStack(7x16)', () => flattenStack(stack7x16)));
results.push(bench('flattenStack(7x64)', () => flattenStack(stack7x64)));

// --- tickBoundaryStack (composite) ---
const tickStack = buildStack(7, 16, 50);
results.push(
  bench('tickStack(7x16)', () => tickBoundaryStack(tickStack), 100, 10000)
);

// --- measure (composite) ---
results.push(bench('measure(16)', () => measure(b16)));
results.push(bench('measure(64)', () => measure(b64)));
results.push(bench('measure(256)', () => measure(b256)));

// --- teleportDeficit ---
results.push(bench('teleportDeficit(256)', () => teleportDeficit(b256)));
results.push(bench('teleportDeficit(1024)', () => teleportDeficit(b1024)));

// --- buleyeanWeight (scalar, should be ~1ns) ---
results.push(bench('buleyeanWeight', () => buleyeanWeight(1000, 500)));

// --- Walker full c0-c3 loop ---
const walkerB = buildBoundary(32, 200);
const walker = createWalker(walkerB);
let rngState = 42;
const fastRng = () => {
  rngState = (rngState * 1664525 + 1013904223) & 0x7fffffff;
  return rngState / 0x7fffffff;
};

results.push(bench('walker c0Choose(32)', () => c0Choose(walker, fastRng)));
results.push(bench('walker c0Update', () => c0Update(walker, 5, 1, 0.1)));
results.push(bench('walker c1Measure(32)', () => c1Measure(walker)));
results.push(bench('walker c2c3Adapt', () => c2c3Adapt(walker)));

// --- sampleComplement ---
const dist16 = complementDistribution(b16);
results.push(
  bench('sampleComplement(16)', () => sampleComplement(dist16, fastRng))
);

report(results);

// Print quadratic scaling evidence for gini
console.log('\n[R1 Gini scaling analysis]');
const giniResults = results.filter((r) => r.name.startsWith('gini'));
for (let i = 1; i < giniResults.length; i++) {
  const ratio = giniResults[i].nsPerOp / giniResults[i - 1].nsPerOp;
  const dimRatio =
    parseInt(giniResults[i].name.match(/\d+/)?.[0] ?? '1') /
    parseInt(giniResults[i - 1].name.match(/\d+/)?.[0] ?? '1');
  console.log(
    `  ${giniResults[i - 1].name} → ${giniResults[i].name}: ${ratio.toFixed(
      1
    )}x slower (dim ${dimRatio}x, expected ${(dimRatio ** 2).toFixed(
      0
    )}x for O(N²))`
  );
}
